using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for richer scenarios ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalEdgeCases))]
    public void CalculateTotal_EdgeCases_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalEdgeCases =>
    [
        (1000.00m, 100, 0.0m, 100_000.00m),   // Large order, no tax
        (1000.00m, 100, 1.0m, 200_000.00m),   // Large order, max tax
        (0.01m, 1, 0.0m, 0.01m),              // Minimum price
        (0.01m, 1, 1.0m, 0.02m),              // Minimum price, max tax
    ];

    // --- CalculateTotal: exception cases ---

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DataRow for common percentages ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off $100")]
    [DataRow(100.00, 25.0, 75.00, DisplayName = "25% off $100")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off $100")]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(49.99, 20.0, 39.992, DisplayName = "Fractional result")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for boundary testing ---

    [TestMethod]
    [DynamicData(nameof(DiscountBoundaryData))]
    public void ApplyDiscount_BoundaryCases_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountBoundaryData =>
    [
        (0.00m, 50m, 0.00m),          // Zero price, any discount
        (999.99m, 0m, 999.99m),       // No discount preserves price
        (999.99m, 100m, 0.00m),       // Full discount
        (0.01m, 50m, 0.005m),         // Smallest meaningful price
    ];

    // --- ApplyDiscount: invalid discount percentages ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(100.01, DisplayName = "Discount exceeds 100%")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice: DataRow for formatting validation ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "USD format")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "EUR format")]
    [DataRow(1000.00, "$", "$1000.00", DisplayName = "Large amount")]
    [DataRow(0.50, "£", "£0.50", DisplayName = "GBP sub-unit")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

